  // Called when a dirty connection is instantiated
  _load() {
    let buffer = '';

    if (!this.path) {
      process.nextTick(() => {
        this.emit('load', 0);
      });
      return;
    }

    this._readStream = fs.createReadStream(this.path, {
      encoding: 'utf-8',
      flags: 'r',
    });

    this._readStream
        .on('error', (err) => {
          if (err.code === 'ENOENT') {
            this.emit('load', 0);
            return;
          }

          this.emit('error', err);
        })
        .on('data', (chunk) => {
